import java.io.*;
public class Main{
    private static int maxNestingDepth(String s){int maxDepth=0,cur=0;for(int i=0;i<s.length();i++){char ch=s.charAt(i);if(ch=='(')cur++;else if(ch==')')cur--;if(cur>maxDepth)maxDepth=cur;}return maxDepth;}
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder sb=new StringBuilder();
        for(int t=0;t<T;t++){
            String line=br.readLine();
            sb.append(maxNestingDepth(line)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

