import sys
def maxNestingDepth(s):
    maxDepth=0
    cur=0
    for ch in s:
        if ch=='(':
            cur+=1
            if cur>maxDepth:
                maxDepth=cur
        elif ch==')':
            cur-=1
    return maxDepth

data=sys.stdin.read().splitlines()
if not data:
    sys.exit()
T=int(data[0].strip())
out=[]
for i in range(1,T+1):
    s=data[i].strip()
    out.append(str(maxNestingDepth(s)))
print('\n'.join(out))
